import type React from 'react';

import * as SeparatorPrimitive from '@radix-ui/react-separator';

import { cn } from '../utils/cn';

/**
 * A visual separator, similar to an `<hr>` element. May be used vertically also.
 *
 */
function Separator({
  className,
  orientation = 'horizontal',
  decorative = true,
  ...props
}: React.ComponentProps<typeof SeparatorPrimitive.Root>) {
  return (
    <SeparatorPrimitive.Root
      data-slot="separator"
      decorative={decorative}
      orientation={orientation}
      className={cn(
        [
          'shrink-0 bg-border',
          'data-[orientation=horizontal]:h-px data-[orientation=vertical]:h-full',
          'data-[orientation=horizontal]:w-full data-[orientation=vertical]:w-px',
        ],
        className
      )}
      {...props}
    />
  );
}

export default Separator;
